from fastapi import FastAPI
from pydantic import BaseModel

app = FastAPI()

class OrderItem(BaseModel):
    product_name: str
    quantity: int
    unit_price: float

class OrderCreate(BaseModel):
    customer_name: str
    items: list[OrderItem]
    notes: str | None = None

