from fastapi import FastAPI
from pydantic import BaseModel, Field, field_validator

app = FastAPI()

class UserProfile(BaseModel):
    username: str = Field(min_length=3, max_length=20)
    bio: str | None = Field(default=None, max_length=500)
    website: str | None = None

    @field_validator("username")
    @classmethod
    def username_alphanumeric(cls, v: str) -> str:
        if not v.isalnum():
            raise ValueError("Username must be alphanumeric")
        return v

    @field_validator("website")
    @classmethod
    def website_must_be_url(cls, v: str | None) -> str | None:
        if v is not None and not v.startswith(("http://", "https://")):
            raise ValueError("Website must start with http:// or https://")
        return v

@app.post("/profile")
def create_profile(profile: UserProfile):
    return profile.model_dump()

from fastapi import FastAPI
from pydantic import BaseModel, Field, model_validator

app = FastAPI()

class EventCreate(BaseModel):
    title: str
    start_time: str
    end_time: str
    max_attendees: int = Field(ge=1)
    current_attendees: int = Field(default=0, ge=0)

    @model_validator(mode="after")
    def validate_event(self):
        if self.end_time == self.start_time:
            raise ValueError("end_time must differ from start_time")
        if self.current_attendees > self.max_attendees:
            raise ValueError("current_attendees cannot exceed max_attendees")
        return self

@app.post("/events", status_code=201)
def create_event(event: EventCreate):
    return event.model_dump()

